using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using verii_metivon_api.Modules.Procurement.Application.Services;
namespace verii_metivon_api.Modules.Procurement.Api;[ApiController,Authorize,Route("api/purchase-orders")]public sealed class PurchaseOrdersController(IPurchaseOrderService s):ControllerBase{[HttpGet]public async Task<IActionResult>List([FromQuery]PurchaseOrderQuery q,CancellationToken ct){var r=await s.GetPagedAsync(q,ct);return StatusCode(r.StatusCode,r);}[HttpPost]public async Task<IActionResult>Create(CreatePurchaseOrderRequest x,CancellationToken ct){var r=await s.CreateAsync(x,ct);return StatusCode(r.StatusCode,r);}[HttpPost("{id:long}/confirm")]public async Task<IActionResult>Confirm(long id,CancellationToken ct){var r=await s.ConfirmAsync(id,ct);return StatusCode(r.StatusCode,r);}[HttpPost("{id:long}/cancel")]public async Task<IActionResult>Cancel(long id,CancellationToken ct){var r=await s.CancelAsync(id,ct);return StatusCode(r.StatusCode,r);}}
